import * as React from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';

function About () {
	return (
		<Box
      sx={{
        display: 'flex',
        flexDirection: 'row',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100vh',
				backgroundColor: 'grey',
				gap: 5,
      }}
    >
			<Box
				sx={{
					marginTop: '56px',
					// display: 'flex',
					// flexDirection: 'row',
					// alignItems: 'center',
					// justifyContent: 'center',
					// height: '80vh',
					backgroundColor: 'blue'
				}}
			>
				<Typography component="h1"
					sx={{
						fontSize: '28px',
						marginBottom: '0px',
						fontWeight: '300',
					}}
				>
					About Me
				</Typography>
			</Box>
			<Box
				sx={{
					marginTop: '56px',
					// display: 'flex',
					// flexDirection: 'row',
					// alignItems: 'center',
					// justifyContent: 'center',
					// height: '80vh',
					backgroundColor: 'blue'
				}}
			>
				<Typography component="h1"
					sx={{
						fontSize: '28px',
						marginBottom: '0px',
						fontWeight: '300',
					}}
				>
					Learn More
				</Typography>
			</Box>

		</Box>
	)
}

export default About;
